import React from "react";

function App() {
  return (
    <div
      style={{
        padding: "30px",
        fontFamily: "Arial"
      }}
    >
      <h1>
        Maternal Health Conflict Resolution Dashboard
      </h1>

      <hr />

      <h2>Pipeline Status</h2>

      <ul>
        <li>Dataset Generation ✓</li>
        <li>Standardization ✓</li>
        <li>Blocking ✓</li>
        <li>Entity Resolution ✓</li>
        <li>Conflict Detection ✓</li>
        <li>Reliability Scoring ✓</li>
        <li>Bayesian Resolution ✓</li>
        <li>Risk Prediction ✓</li>
      </ul>

      <h2>Current Results</h2>

      <p>Total Patients: 5000</p>
      <p>Total Records: 20000</p>
      <p>Resolved Patients: 5000</p>
      <p>High Risk Patients: 693</p>

    </div>
  );
}

export default App;
